import { useState } from "react";

export default function Counter() {
const [count,setCount]=useState(0);

  return <div>
      <spa>
          <b>Count:</b>
      </spa>
      <br/>
      <button onClick={()=>{setCount(count+1)}}>Increase</button>
  </div>;
}
